/* Chart.min.js placeholder for DeCoupled-AI dashboard
 * Lightweight stub providing the minimal Canvas-based scatter/line rendering
 * the metrics page uses. Not the full Chart.js bundle.
 */
window.Chart = (function () {
    function Chart(ctx, opts) {
        this.ctx = typeof ctx === "string" ? document.querySelector(ctx) : ctx;
        this.opts = opts || {};
        if (this.ctx && this.ctx.getContext) {
            this.ctx = this.ctx.getContext("2d");
        }
    }
    Chart.prototype.update = function () {};
    Chart.prototype.destroy = function () {};
    Chart.prototype.render = function () {
        if (!this.ctx || !this.ctx.canvas) return;
        const c = this.ctx.canvas;
        this.ctx.clearRect(0, 0, c.width, c.height);
        const data = (this.opts.data && this.opts.data.datasets) || [];
        const max = Math.max(...data.flatMap(d => d.data || []), 1);
        data.forEach((ds, i) => {
            this.ctx.strokeStyle = ds.borderColor || ["#63b3ed", "#9f7aea", "#48bb78"][i % 3];
            this.ctx.beginPath();
            (ds.data || []).forEach((v, j) => {
                const x = (j / Math.max(ds.data.length - 1, 1)) * c.width;
                const y = c.height - (v / max) * c.height;
                if (j === 0) this.ctx.moveTo(x, y); else this.ctx.lineTo(x, y);
            });
            this.ctx.stroke();
        });
    };
    Chart.register = function () {};
    return Chart;
})();
